import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { AutorService } from '../../services/autor.service';
import { Autor } from '../../models/autor';

@Component({
  selector: 'app-autores',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './autores.component.html',
  styleUrl: './autores.component.css'
})
export class AutoresComponent implements OnInit {

  autores: Autor[] = [];
  loading = false;
  editingId: number | null = null;
  error: string | null = null;

  form = this.fb.group({
    nome: ['', [Validators.required, Validators.maxLength(40)]]
  });

  constructor(private fb: FormBuilder, private service: AutorService) {}

  ngOnInit(): void {
    this.load();
  }

  load(): void {
    this.loading = true;
    this.error = null;
    this.service.list().subscribe({
      next: (data) => this.autores = data,
      error: () => this.error = 'Falha ao carregar autores.',
      complete: () => this.loading = false
    });
  }

  startEdit(a: Autor): void {
    this.editingId = a.id;
    this.form.setValue({ nome: a.nome });
  }

  cancel(): void {
    this.editingId = null;
    this.form.reset();
  }

  save(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    const nome = this.form.value.nome!.trim();

    this.loading = true;
    this.error = null;

    const req$ = this.editingId
      ? this.service.update(this.editingId, nome)
      : this.service.create(nome);

    req$.subscribe({
      next: () => { this.cancel(); this.load(); },
      error: () => this.error = 'Falha ao salvar autor.',
      complete: () => this.loading = false
    });
  }

  remove(a: Autor): void {
    if (!confirm(`Remover autor "${a.nome}"?`)) return;
    this.loading = true;
    this.error = null;
    this.service.delete(a.id).subscribe({
      next: () => this.load(),
      error: () => this.error = 'Falha ao remover autor (pode estar vinculado a livro).',
      complete: () => this.loading = false
    });
  }
}
<div class="d-flex align-items-center justify-content-between mb-3">
  <h2>Autores</h2>
</div>

<div class="alert alert-danger" *ngIf="error">{{error}}</div>

<div class="card mb-3">
  <div class="card-body">
    <h5 class="card-title">{{ editingId ? 'Editar Autor' : 'Novo Autor' }}</h5>

    <form [formGroup]="form" (ngSubmit)="save()" class="row g-2 align-items-end">
      <div class="col-md-6">
        <label class="form-label">Nome</label>
        <input class="form-control" formControlName="nome" placeholder="Ex: Machado de Assis" />
        <div class="text-danger mt-1" *ngIf="form.controls.nome.touched && form.controls.nome.invalid">
          Nome é obrigatório (máx 40).
        </div>
      </div>

      <div class="col-md-6 d-flex gap-2">
        <button class="btn btn-primary" type="submit" [disabled]="loading">
          {{ editingId ? 'Salvar' : 'Adicionar' }}
        </button>
        <button class="btn btn-outline-secondary" type="button" (click)="cancel()" *ngIf="editingId" [disabled]="loading">
          Cancelar
        </button>
      </div>
    </form>
  </div>
</div>

<div class="card">
  <div class="card-body">
    <div class="d-flex justify-content-between">
      <h5 class="card-title mb-3">Lista</h5>
      <span *ngIf="loading" class="text-muted">carregando...</span>
    </div>

    <table class="table table-sm table-hover align-middle">
      <thead>
        <tr>
          <th style="width: 90px;">ID</th>
          <th>Nome</th>
          <th style="width: 160px;"></th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let a of autores">
          <td>{{a.id}}</td>
          <td>{{a.nome}}</td>
          <td class="text-end">
            <button class="btn btn-sm btn-outline-primary me-2" (click)="startEdit(a)">Editar</button>
            <button class="btn btn-sm btn-outline-danger" (click)="remove(a)">Remover</button>
          </td>
        </tr>
      </tbody>
    </table>
  </div>
</div>
